#!/usr/bin/env dotnet
// Find the earliest Friday the 13th in the proleptic Gregorian calendar (from 0001-01-01)
// and count total Friday the 13ths in a full 400-year cycle.

// --- Earliest Friday the 13th ---
var date = new DateTime(1, 1, 13); // start checking the 13th of each month
while (date.DayOfWeek != DayOfWeek.Friday)
{
    date = date.AddMonths(1);
}
Console.WriteLine($"Earliest Friday the 13th: {date:yyyy-MM-dd} ({date:dddd})");

// --- Count in a full 400-year cycle (0001-01-01 to 0400-12-31) ---
int count = 0;
var start = new DateTime(1, 1, 13);
var end = new DateTime(400, 12, 31);

var current = start;
while (current <= end)
{
    if (current.DayOfWeek == DayOfWeek.Friday)
        count++;
    current = current.AddMonths(1);
}

Console.WriteLine($"Friday the 13ths in a 400-year cycle: {count}");

// --- Bonus: distribution by month ---
var byMonth = new int[12];
current = start;
while (current <= end)
{
    if (current.DayOfWeek == DayOfWeek.Friday)
        byMonth[current.Month - 1]++;
    current = current.AddMonths(1);
}

Console.WriteLine("\nDistribution by month:");
for (int m = 0; m < 12; m++)
    Console.WriteLine($"  {new DateTime(2000, m + 1, 1):MMMM,-10} {byMonth[m]}");
EOF
